namespace sv_6a8ef01025ca4152ac9b170b56370531.Services;

public class WizardState
{
    public const int TotalSteps = 4;

    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3: References
    public List<Reference> References { get; set; } = [];

    // Track which steps the user has completed
    private readonly HashSet<int> _completedSteps = [];

    public IReadOnlySet<int> CompletedSteps => _completedSteps;

    public void MarkCompleted(int step) => _completedSteps.Add(step);

    public bool IsStepCompleted(int step) => _completedSteps.Contains(step);
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class Reference
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

