﻿@inherits LayoutComponentBase
@inject sv_6a8ef01025ca4152ac9b170b56370531.Services.WizardState Wizard

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <div class="d-flex align-items-center gap-2 flex-grow-1">
                    @for (var i = 1; i <= sv_6a8ef01025ca4152ac9b170b56370531.Services.WizardState.TotalSteps; i++)
                    {
                        var step = i;
                        var isActive = step == CurrentStep;
                        var isCompleted = Wizard.IsStepCompleted(step);
                        <a href="@StepUrl(step)"
                           class="badge @(isCompleted ? "bg-success" : isActive ? "bg-primary" : "bg-secondary")"
                           style="text-decoration:none; font-size:0.9rem;">
                            @StepLabel(step)
                        </a>
                    }
                    <span class="ms-auto text-muted">Step @CurrentStep of @sv_6a8ef01025ca4152ac9b170b56370531.Services.WizardState.TotalSteps</span>
                </div>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

